// Extract embedding from Gemini response
const embedding = $input.item.json.embedding.values;
const document = $input.item.json;

// Prepare data for Supabase Vector Store
return {
  json: {
    id: document.id,
    content: document.content,
    embedding: embedding,
    metadata: document.metadata
  }
};

return {
  json: {
    message: 'Brand knowledge embeddings created and stored successfully',
    documents_processed: $input.item.json.length || 1,
    timestamp: new Date().toISOString()
  }
};
